import {
  Component,
  createContext,
  createEffect,
  createSignal,
  mergeProps,
  onCleanup,
  useContext,
} from 'solid-js';
import { Portal } from 'solid-js/web';
import { cn } from '@utils/cn';
import { SelectZoneItemProps, SelectZoneProps } from './select-zone.types';

// ─── Context ──────────────────────────────────────────────────────────────────

interface SelectZoneContextValue {
  registerItem: (key: string, el: HTMLElement) => void;
  unregisterItem: (key: string) => void;
  isSelected: (key: string) => boolean;
}

const SelectZoneContext = createContext<SelectZoneContextValue>();

// ─── SelectZone ───────────────────────────────────────────────────────────────

const DEFAULT_PROPS = {
  additive: true,
  scrollThreshold: 40,
  scrollSpeed: 12,
  disabled: false,
};

export const SelectZone: Component<SelectZoneProps> = props => {
  const p = mergeProps(DEFAULT_PROPS, props);

  // Map từ itemKey → DOM element (đăng ký bởi SelectZoneItem)
  const itemMap = new Map<string, HTMLElement>();

  // Tập hợp các key đang được chọn
  const [selectedKeys, setSelectedKeys] = createSignal<Set<string>>(new Set());

  // Overlay rect: null = ẩn, có giá trị = đang kéo
  const [overlayRect, setOverlayRect] = createSignal<{
    x: number;
    y: number;
    w: number;
    h: number;
  } | null>(null);

  let rootEl!: HTMLDivElement;

  // ── Helpers ─────────────────────────────────────────────────────────────────

  /**
   * Tính giao nhau AABB.
   * selLeft/Top/Right/Bottom: document coordinates (pageX/Y).
   * el.getBoundingClientRect(): viewport coordinates → convert sang document.
   */
  function intersects(
    selLeft: number,
    selTop: number,
    selRight: number,
    selBottom: number,
    el: HTMLElement,
  ): boolean {
    const r = el.getBoundingClientRect();
    const docLeft = r.left + window.scrollX;
    const docTop = r.top + window.scrollY;
    const docRight = r.right + window.scrollX;
    const docBottom = r.bottom + window.scrollY;
    return docRight > selLeft && docLeft < selRight && docBottom > selTop && docTop < selBottom;
  }

  /**
   * Tính selection.
   * startPageX/Y, currPageX/Y: document coordinates.
   */
  function computeSelection(
    startPageX: number,
    startPageY: number,
    currPageX: number,
    currPageY: number,
  ): Set<string> {
    const selLeft = Math.min(startPageX, currPageX);
    const selTop = Math.min(startPageY, currPageY);
    const selRight = Math.max(startPageX, currPageX);
    const selBottom = Math.max(startPageY, currPageY);

    const hit = new Set<string>();
    itemMap.forEach(function checkItem(el, key) {
      if (intersects(selLeft, selTop, selRight, selBottom, el)) {
        hit.add(key);
      }
    });
    return hit;
  }

  // ── Drag state ───────────────────────────────────────────────────────────────

  // startPageX/Y: document coordinates — cố định suốt drag, không bị ảnh hưởng bởi scroll
  let startPageX = 0;
  let startPageY = 0;
  let isDragging = false;
  let isAdditive = false;
  let prevKeys: Set<string> = new Set();
  let rafId = 0;
  let lastClientX = 0;
  let lastClientY = 0;

  // ── Auto-scroll loop ─────────────────────────────────────────────────────────

  function scrollLoop() {
    if (!isDragging) return;

    const threshold = p.scrollThreshold;
    const speed = p.scrollSpeed;
    const vw = window.innerWidth;
    const vh = window.innerHeight;
    const cx = lastClientX;
    const cy = lastClientY;

    let dx = 0;
    let dy = 0;

    if (cx < threshold) dx = -speed * (1 - cx / threshold);
    else if (cx > vw - threshold) dx = speed * (1 - (vw - cx) / threshold);

    if (cy < threshold) dy = -speed * (1 - cy / threshold);
    else if (cy > vh - threshold) dy = speed * (1 - (vh - cy) / threshold);

    if (dx !== 0 || dy !== 0) {
      window.scrollBy(dx, dy);
      // startPageX/Y KHÔNG thay đổi — nó là điểm neo trong document space
    }

    // Cập nhật overlay sau mỗi frame (kể cả khi chỉ scroll mà chuột đứng yên)
    updateOverlay(cx, cy);

    rafId = requestAnimationFrame(scrollLoop);
  }

  // ── Overlay update ───────────────────────────────────────────────────────────

  function updateOverlay(currClientX: number, currClientY: number) {
    // Convert cursor về document coordinates
    const currPageX = currClientX + window.scrollX;
    const currPageY = currClientY + window.scrollY;

    // Overlay rect tính trong document space
    const docLeft = Math.min(startPageX, currPageX);
    const docTop = Math.min(startPageY, currPageY);
    const w = Math.abs(currPageX - startPageX);
    const h = Math.abs(currPageY - startPageY);

    // Convert sang viewport để render (position: fixed dùng viewport coords)
    setOverlayRect({
      x: docLeft - window.scrollX,
      y: docTop - window.scrollY,
      w,
      h,
    });

    // Selection dùng document coordinates
    const hit = computeSelection(startPageX, startPageY, currPageX, currPageY);

    let next: Set<string>;
    if (isAdditive) {
      // Toggle per-item: item trong prevKeys bị drag đè → deselect; item mới → select
      next = new Set(prevKeys);
      hit.forEach(k => {
        if (prevKeys.has(k)) next.delete(k);
        else next.add(k);
      });
    } else {
      next = hit;
    }
    setSelectedKeys(next);
  }

  // ── Event handlers ───────────────────────────────────────────────────────────

  function onMouseDown(e: MouseEvent) {
    if (p.disabled) return;
    // Chỉ xử lý click trái, không xử lý trên scrollbar, input, button, a
    if (e.button !== 0) return;
    const target = e.target as HTMLElement;
    if (target.closest('input, button, a, textarea, select, [data-no-select]')) return;

    isDragging = false;
    // Lưu điểm bắt đầu trong document space — bất biến suốt drag
    startPageX = e.clientX + window.scrollX;
    startPageY = e.clientY + window.scrollY;
    lastClientX = e.clientX;
    lastClientY = e.clientY;
    isAdditive = e.shiftKey || e.ctrlKey || e.metaKey;
    prevKeys = isAdditive ? new Set(selectedKeys()) : new Set();

    document.addEventListener('mousemove', onMouseMove);
    document.addEventListener('mouseup', onMouseUp);
  }

  function onMouseMove(e: MouseEvent) {
    lastClientX = e.clientX;
    lastClientY = e.clientY;

    // So sánh trong document space để tránh nhiễu từ scroll
    const dx = e.clientX + window.scrollX - startPageX;
    const dy = e.clientY + window.scrollY - startPageY;

    if (!isDragging) {
      // Chỉ bắt đầu drag khi kéo ít nhất 4px để tránh nhầm với click
      if (Math.abs(dx) < 4 && Math.abs(dy) < 4) return;
      isDragging = true;
      rafId = requestAnimationFrame(scrollLoop);
    }

    updateOverlay(e.clientX, e.clientY);
  }

  function onMouseUp(e: MouseEvent) {
    document.removeEventListener('mousemove', onMouseMove);
    document.removeEventListener('mouseup', onMouseUp);

    cancelAnimationFrame(rafId);
    isDragging = false;

    if (overlayRect() !== null) {
      setOverlayRect(null);
      // Thông báo selection cuối cùng
      p.onSelect?.(new Set(selectedKeys()));
    } else {
      // Không drag → click đơn → deselect tất cả (nếu không additive)
      if (!isAdditive) {
        const target = e.target as HTMLElement;
        const item = target.closest('[data-select-key]') as HTMLElement | null;
        if (!item) {
          setSelectedKeys(new Set<string>());
          p.onSelect?.(new Set<string>());
        }
      }
    }
  }

  // ── Context value ────────────────────────────────────────────────────────────

  const contextValue: SelectZoneContextValue = {
    registerItem(key, el) {
      itemMap.set(key, el);
    },
    unregisterItem(key) {
      itemMap.delete(key);
    },
    isSelected(key) {
      return selectedKeys().has(key);
    },
  };

  // ── Đồng bộ controlled value ─────────────────────────────────────────────────

  createEffect(function syncControlledValue() {
    const v = p.value;
    if (v !== undefined) setSelectedKeys(new Set(v));
  });

  // ── Cleanup khi unmount ──────────────────────────────────────────────────────

  createEffect(function mountListeners() {
    rootEl.addEventListener('mousedown', onMouseDown);
    onCleanup(function unmountListeners() {
      rootEl.removeEventListener('mousedown', onMouseDown);
      document.removeEventListener('mousemove', onMouseMove);
      document.removeEventListener('mouseup', onMouseUp);
      cancelAnimationFrame(rafId);
    });
  });

  // ── Render ───────────────────────────────────────────────────────────────────

  return (
    <SelectZoneContext.Provider value={contextValue}>
      <div ref={rootEl} class={cn('sz01', p.class?.root)}>
        {p.children}

        {/* Selection overlay — render qua Portal để tránh ảnh hưởng layout */}
        {overlayRect() && (
          <Portal mount={document.body}>
            <div
              class={cn('sz02', p.class?.overlay)}
              style={{
                left: `${overlayRect()!.x}px`,
                top: `${overlayRect()!.y}px`,
                width: `${overlayRect()!.w}px`,
                height: `${overlayRect()!.h}px`,
              }}
            />
          </Portal>
        )}
      </div>
    </SelectZoneContext.Provider>
  );
};

// ─── SelectZoneItem ───────────────────────────────────────────────────────────

export const SelectZoneItem: Component<SelectZoneItemProps> = props => {
  const ctx = useContext(SelectZoneContext);
  if (!ctx) throw new Error('SelectZoneItem must be used inside <SelectZone>');

  let el!: HTMLDivElement;

  createEffect(function registerOnMount() {
    ctx.registerItem(props.itemKey, el);
    onCleanup(function unregisterOnUnmount() {
      ctx.unregisterItem(props.itemKey);
    });
  });

  const isSelected = () => ctx.isSelected(props.itemKey);

  return (
    <div ref={el} data-select-key={props.itemKey} class={cn('sz03', props.class)}>
      {props.children(isSelected)}
    </div>
  );
};
